"""
MCP Integration for OpenCode TUI
Provides MCP client/server capabilities within the interactive mode
"""

import asyncio
from contextlib import asynccontextmanager
from typing import Optional, AsyncIterator
from pathlib import Path

from mcp import ClientSession, StdioServerParameters
from mcp.client.stdio import stdio_client

from rich.console import Console

from .mcp_server_wrapper import OpenCodeMCPServer
from .tools import ToolManager
from .config import Config

console = Console()


class MCPIntegration:
    """
    Manages MCP integration for OpenCode TUI
    Supports both embedded server mode and external client mode
    """
    
    def __init__(
        self, 
        tool_manager: ToolManager,
        config: Config,
        mode: str = "embedded"
    ):
        """
        Initialize MCP integration
        
        Args:
            tool_manager: Existing ToolManager instance
            config: Application configuration
            mode: "embedded" (server in-process) or "client" (connect to external)
        """
        self.tool_manager = tool_manager
        self.config = config
        self.mode = mode
        self.server: Optional[OpenCodeMCPServer] = None
        self.client_session: Optional[ClientSession] = None
        self._server_task: Optional[asyncio.Task] = None
        
    async def start(self):
        """Start MCP integration based on mode"""
        if self.mode == "embedded":
            await self._start_embedded_server()
        elif self.mode == "client":
            await self._start_client()
        else:
            raise ValueError(f"Unknown MCP mode: {self.mode}")
    
    async def _start_embedded_server(self):
        """Start MCP server embedded in TUI process"""
        console.print("[dim]🔌 Starting embedded MCP server...[/dim]")
        
        self.server = OpenCodeMCPServer(self.tool_manager)
        
        # Run server in background task (for external model connections)
        # Note: Server uses STDIO, so external models can spawn this as subprocess
        console.print(f"[dim]✓ MCP server ready for external connections[/dim]")
        console.print(f"[dim]  Working dir: {self.tool_manager.working_dir}[/dim]")
    
    async def _start_client(self):
        """Connect to external MCP server"""
        console.print("[dim]🔌 Connecting to external MCP server...[/dim]")
        
        # Get server path from config or default
        server_script = self.config.mcp.get("server_script", "mcp_server_wrapper.py")
        
        server_params = StdioServerParameters(
            command="python",
            args=[server_script],
            env=None
        )
        
        # Connect to server
        async with stdio_client(server_params) as (read, write):
            async with ClientSession(read, write) as session:
                await session.initialize()
                self.client_session = session
                
                # List available tools
                tools = await session.list_tools()
                console.print(f"[dim]✓ Connected to MCP server ({len(tools.tools)} tools)[/dim]")
                
                # Keep session alive
                await asyncio.Event().wait()
    
    async def stop(self):
        """Stop MCP integration"""
        if self._server_task:
            self._server_task.cancel()
            try:
                await self._server_task
            except asyncio.CancelledError:
                pass
        
        if self.client_session:
            # Client cleanup handled by context manager
            pass
    
    def get_mcp_info(self) -> dict:
        """Get MCP status information for /doctor command"""
        return {
            "mode": self.mode,
            "status": "active" if (self.server or self.client_session) else "inactive",
            "working_dir": str(self.tool_manager.working_dir),
            "tools_available": len(self.tool_manager.get_available_tools())
        }
    
    @asynccontextmanager
    async def external_model_connection(self) -> AsyncIterator[dict]:
        """
        Context manager for external models to get connection info
        
        Usage:
            async with mcp_integration.external_model_connection() as conn_info:
                # Use conn_info to configure external model
                pass
        """
        if self.mode != "embedded":
            raise RuntimeError("external_model_connection only available in embedded mode")
        
        # Provide connection info for external models
        conn_info = {
            "transport": "stdio",
            "command": "python",
            "args": ["-m", "opencode.mcp_server_wrapper"],
            "working_dir": str(self.tool_manager.working_dir),
            "capabilities": {
                "tools": ["file_read", "file_write", "grep_search", "bash_execute"],
                "resources": ["working_directory"],
                "prompts": []
            }
        }
        
        yield conn_info


# Helper function for integration into InteractiveMode
async def integrate_mcp(interactive_mode) -> MCPIntegration:
    """
    Integrate MCP into existing InteractiveMode instance
    
    Args:
        interactive_mode: InteractiveMode instance
        
    Returns:
        MCPIntegration instance
    """
    # Check if MCP is enabled in config
    mcp_config = interactive_mode.config.mcp
    enabled = mcp_config.enabled
    
    if not enabled:
        return None
    
    mode = mcp_config.mode
    
    mcp_integration = MCPIntegration(
        tool_manager=interactive_mode.tool_manager,
        config=interactive_mode.config,
        mode=mode
    )
    
    await mcp_integration.start()
    
    return mcp_integration


# Extension to InteractiveMode for MCP commands
class MCPCommands:
    """MCP-specific commands for TUI"""
    
    @staticmethod
    def add_commands_to_completer(completer):
        """Add MCP commands to command completer"""
        completer.commands.update({
            '/mcp': 'MCP server status and control',
            '/mcp status': 'Show MCP server status',
            '/mcp info': 'Show connection information for external models',
            '/mcp restart': 'Restart MCP server'
        })
    
    @staticmethod
    async def handle_mcp_command(interactive_mode, args: str):
        """Handle /mcp commands"""
        if not hasattr(interactive_mode, 'mcp_integration') or not interactive_mode.mcp_integration:
            console.print("[yellow]MCP not enabled. Set 'mcp.enabled: true' in config.yaml[/yellow]")
            return
        
        parts = args.strip().split() if args else []
        subcommand = parts[0] if parts else "status"
        
        if subcommand == "status":
            info = interactive_mode.mcp_integration.get_mcp_info()
            console.print(f"[cyan]MCP Server Status[/cyan]")
            console.print(f"  Mode: {info['mode']}")
            console.print(f"  Status: {info['status']}")
            console.print(f"  Working Dir: {info['working_dir']}")
            console.print(f"  Tools Available: {info['tools_available']}")
        
        elif subcommand == "info":
            if interactive_mode.mcp_integration.mode != "embedded":
                console.print("[yellow]Connection info only available in embedded mode[/yellow]")
                return
            
            async with interactive_mode.mcp_integration.external_model_connection() as conn:
                console.print("[cyan]MCP Connection Information for External Models[/cyan]")
                console.print(f"  Transport: {conn['transport']}")
                console.print(f"  Command: {conn['command']}")
                console.print(f"  Args: {' '.join(conn['args'])}")
                console.print(f"  Working Dir: {conn['working_dir']}")
                console.print(f"\n[dim]External models can connect using these parameters[/dim]")
        
        elif subcommand == "restart":
            console.print("[yellow]Restarting MCP server...[/yellow]")
            await interactive_mode.mcp_integration.stop()
            await interactive_mode.mcp_integration.start()
            console.print("[green]✓ MCP server restarted[/green]")
        
        else:
            console.print(f"[yellow]Unknown MCP command: {subcommand}[/yellow]")
            console.print("[dim]Available: status, info, restart[/dim]")
